@Action
def get_account_details() -> dict:
    """Get linkedAccountNumber and linkedAccountSystem for Internet service"""
    try:
      subscriptions = state["$session.params.subscriptionsList"]

      result = {
          "linkedAccountNumber": None,
          "linkedAccountSystem": None
      }

      if not subscriptions:
          return result

      for item in subscriptions:
          service_category = item.get("serviceCategory", {}).get("english", "").strip().lower()

          if service_category == "business phone":
              result["linkedAccountNumber"] = item.get("linkedAccountNumber")
              result["linkedAccountSystem"] = item.get("linkedAccountSystem")
              return result

      return result
    except Exception as e:
      error="Code Block Error"
      print(f"Something went wrong with the code block execution: {e}")
      return {"error":error}
      
@Action
def check_saved_intent(counter:int) -> int:
    """Update counter based on intent and current value"""
    try:
      counter=int(counter)
      intent_map = state["$session.params.forcedSelfServIntent"]

      saved_intent = state["$session.params.savedIntent"]

      if intent_map.get(saved_intent) == True:
          if counter == 0:
              counter += 1
              return counter
          else:
              counter +=1
              return counter
      else:
          return counter
    except Exception as e:
        print(f"Something went wrong with the code block execution: {e}")
        return -3
